def get_000001_sz_daily_full() -> pd.DataFrame:
    """返回 000001.SZ 2023H1 完整日线 DataFrame（100 行），含 amount 代理列。

    来源：AKShare stock_zh_a_hist(symbol='000001', period='daily', adjust='')
    成交量单位：手（1 手 = 100 股）；amount = close × volume × 100（元近似值）
    """
    df = make_ohlcv_df(RECORDS_000001_SZ_2023H1)
    df["amount"] = df["close"] * df["volume"] * 100
    return df


def get_extreme_outlier_df() -> pd.DataFrame:
    """返回包含极端涨幅（>20%）的 DataFrame，用于算法边界单元测试。
    见 EXTREME_RECORDS[0].description 中的说明。
    """
    return EXTREME_RECORDS[0]["data"]


def get_volume_spike_df(normal_count: int = 50, spike_volume: int = 0) -> pd.DataFrame:
    """构造包含成交量尖峰的 DataFrame，用于 _check_volume_anomalies 单元测试。

    Args:
        normal_count: 正常成交日天数（须 > 25 使阈值稳定）
        spike_volume: 尖峰成交量（默认 base_volume * 50，须远大于 mean + 5*std）

    数据说明：base volume 213_447_200 来自 000001.SZ 2023-01-03 真实成交量；
    默认 spike = 50 倍，模拟重大事件日（如并购、指数调整）异常涌入场景。
    """
    base_volume = 213_447_200
    effective_spike = spike_volume if spike_volume > 0 else base_volume * 50  # 约 107 亿股
    base = date(2023, 1, 1)
    dates = []
    volumes = []
    day = base
    count = 0
    while count < normal_count + 1:
        if day.weekday() < 5:
            if count < normal_count:
                volumes.append(base_volume)
            else:
                volumes.append(effective_spike)
            dates.append(day.strftime("%Y-%m-%d"))
            count += 1
        day += timedelta(days=1)
    return pd.DataFrame({"date": dates, "volume": volumes})
